class Product { final String sku, name, category, unit; final double unitPrice; final double? wholesalePrice; final int stockQuantity; final List<String> imageUrls; final DateTime lastUpdated; Product({required this.sku, required this.name, required this.category, required this.unit, required this.unitPrice, this.wholesalePrice, required this.stockQuantity, required this.imageUrls, required this.lastUpdated}); factory Product.fromJson(Map<String, dynamic> json) => Product(sku: json['sku']??'', name: json['name']??'', category: json['category']??'', unit: json['unit']??'', unitPrice: (json['unit_price'] as num?)?.toDouble()??0.0, wholesalePrice: (json['wholesale_price'] as num?)?.toDouble(), stockQuantity: json['stock_quantity'] as int? ??0, imageUrls: (json['image_urls'] as List<dynamic>?)?.cast<String>()??[], lastUpdated: json['last_updated']!=null? DateTime.parse(json['last_updated']):DateTime.now()); Map<String, dynamic> toJson() => {'sku':sku, 'name':name, 'category':category, 'unit':unit, 'unit_price':unitPrice, 'wholesale_price':wholesalePrice, 'stock_quantity':stockQuantity, 'image_urls':imageUrls, 'last_updated':lastUpdated.toIso8601String()}; }
